 27→    const criteriaResults = mapAnalysisResults(data);
 28→    return calculateEngineScores(criteriaResults);
 29→  }, [data]);
 30→
 31→  const handleDownloadPDF = async () => {
 32→    const element = document.getElementById('full-pdf-report');
 33→    if (!element) return;
 34→
 35→    setIsExporting(true);
 36→    try {
 37→      // Wait a moment for the hidden div to render properly
 38→      await new Promise(resolve => setTimeout(resolve, 500));
 39→
 40→      const canvas = await html2canvas(element, {
 41→        scale: 2,
 42→        useCORS: true,
 43→        logging: false,
 44→        windowWidth: 1000 // Force width to match container style
 45→      });
 46→
 47→      const imgData = canvas.toDataURL('image/jpeg', 0.95);
 48→      const pdf = new jsPDF({
 49→        orientation: 'portrait',
 50→        unit: 'mm',
 51→        format: 'a4'
 52→      });
 53→
 54→      const pdfWidth = pdf.internal.pageSize.getWidth();
 55→      const pdfHeight = pdf.internal.pageSize.getHeight();
 56→      const imgWidth = pdfWidth;
 57→      const imgHeight = (canvas.height * imgWidth) / canvas.width;
 58→      
 59→      let heightLeft = imgHeight;
 60→      let position = 0;
 61→
 62→      // First page
 63→      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 64→      heightLeft -= pdfHeight;
 65→
 66→      // Subsequent pages if content overflows
 67→      while (heightLeft > 0) {
 68→        position = heightLeft - imgHeight;
 69→        pdf.addPage();
 70→        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 71→        heightLeft -= pdfHeight;
 72→      }
 73→      
 74→      const hostname = new URL(data.url).hostname;
 75→      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
 76→    } catch (err) {
 77→      console.error('PDF Export failed', err);
