110→          <p className="text-gray-400 text-sm">Analysé le {new Date(data.timestamp).toLocaleDateString()} à {new Date(data.timestamp).toLocaleTimeString()}</p>
111→        </div>
112→        
113→        {onNewAnalysis && (
