  59→// Animated number hook for smooth credit transitions
  60→const useAnimatedNumber = (value: number, duration = 600) => {
  61→  const [display, setDisplay] = useState(value);
  62→  const prevValue = useRef(value);
  63→  useEffect(() => {
  64→    if (prevValue.current === value) return;
  65→    const start = prevValue.current;
  66→    const diff = value - start;
  67→    const startTime = performance.now();
  68→    const animate = (now: number) => {
  69→      const progress = Math.min((now - startTime) / duration, 1);
  70→      const eased = 1 - Math.pow(1 - progress, 3);
  71→      setDisplay(Math.round(start + diff * eased));
  72→      if (progress < 1) requestAnimationFrame(animate);
  73→    };
  74→    requestAnimationFrame(animate);
  75→    prevValue.current = value;
  76→  }, [value, duration]);
  77→  return display;
  78→};
