 452→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
 453→    const timestamp = new Date().toISOString();
 454→    const solutionWithMeta = { ...solution, timestamp };
 455→
 456→    setAnalysisData(prev => {
 457→        if (!prev || prev.timestamp !== analysisId) return prev;
 458→        
