 1→import { AIEngine, ENGINE_WEIGHTS, ENGINE_PROFILES, getScoreLevel } from '../config/engine-weights';
 2→
 3→/**
 4→ * Résultat d'un critère individuel issu de l'analyse AEO existante.
 5→ */
 6→export interface CriterionResult {
 7→  id: string;           // ex: 'AEO-TECH-01', 'AEO-DATA-03'
 8→  passed: boolean;      // critère validé ou non
 9→  score: number;        // score brut du critère (0 ou 1 dans le système actuel)
10→  maxPoints: number;    // points max possibles (1 dans le système actuel)
11→  category: string;     // catégorie parente (ex: 'technical')
12→}
13→
14→/**
15→ * Score calculé pour un moteur IA spécifique
16→ */
17→export interface EngineScore {
18→  engineId: AIEngine;
19→  engineName: string;
20→  engineIcon: string;
21→  engineColor: string;
22→  score: number;          // 0-100
23→  level: { label: string; emoji: string; labelEn: string };
24→  description: string;
25→  topStrengths: string[];
26→  topWeaknesses: string[];
27→}
28→
29→/**
30→ * Calcule les sous-scores par moteur à partir des résultats d'analyse existants.
31→ *
32→ * ALGORITHME :
33→ * 1. Pour chaque moteur, on prend tous les critères analysés
34→ * 2. On multiplie le score de chaque critère par le coefficient du moteur
35→ * 3. On divise par le total des points max pondérés
36→ * 4. On normalise sur 100
37→ *
38→ * Aucun appel API — calcul purement mathématique.
39→ */
40→export function calculateEngineScores(criteriaResults: CriterionResult[]): EngineScore[] {
41→  const engines: AIEngine[] = ['chatgpt', 'perplexity', 'gemini'];
42→
43→  return engines.map((engineId) => {
44→    let weightedScore = 0;
45→    let weightedMax = 0;
46→    const strengths: Array<{ id: string; weight: number }> = [];
47→    const weaknesses: Array<{ id: string; weight: number }> = [];
48→
49→    criteriaResults.forEach((criterion) => {
50→      const weight = ENGINE_WEIGHTS[criterion.id]?.[engineId] ?? 1.0;
51→      const criterionWeightedMax = criterion.maxPoints * weight;
52→
53→      weightedMax += criterionWeightedMax;
54→
55→      if (criterion.passed) {
56→        weightedScore += criterion.score * weight;
57→        if (weight >= 1.3) {
58→          strengths.push({ id: criterion.id, weight });
59→        }
60→      } else {
61→        if (weight >= 1.3) {
62→          weaknesses.push({ id: criterion.id, weight });
63→        }
64→      }
65→    });
66→
67→    const normalizedScore = weightedMax > 0
68→      ? Math.round((weightedScore / weightedMax) * 100)
69→      : 0;
70→
71→    const profile = ENGINE_PROFILES[engineId];
72→    const level = getScoreLevel(normalizedScore);
73→
74→    strengths.sort((a, b) => b.weight - a.weight);
75→    weaknesses.sort((a, b) => b.weight - a.weight);
76→
77→    return {
78→      engineId,
79→      engineName: profile.name,
80→      engineIcon: profile.icon,
81→      engineColor: profile.color,
82→      score: normalizedScore,
83→      level,
84→      description: profile.description,
85→      topStrengths: strengths.slice(0, 3).map(s => s.id),
86→      topWeaknesses: weaknesses.slice(0, 3).map(w => w.id),
87→    };
88→  });
89→}
